#include <bits/stdc++.h>
using namespace std;

// --- TOP-DOWN (Memoization) ---
const int MAXN = 1e6 + 5;
long long memo[MAXN];

long long fib_top(int n) {
    if (n <= 1) return n;
    if (memo[n] != -1) return memo[n];
    return memo[n] = fib_top(n-1) + fib_top(n-2);
}

// --- BOTTOM-UP (Tabulation) ---
long long fib_bottom(int n) {
    if (n <= 1) return n;
    vector<long long> dp(n+1);
    dp[0] = 0; dp[1] = 1;
    for (int i = 2; i <= n; i++)
        dp[i] = dp[i-1] + dp[i-2];
    return dp[n];
}

int main() {
    memset(memo, -1, sizeof(memo));
    int n; cin >> n;
    cout << fib_top(n) << "\n";
    cout << fib_bottom(n) << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, amount;
    cin >> n >> amount;
    vector<int> coins(n);
    for (auto& c : coins) cin >> c;

    // dp[i] = minimum coins to make amount i
    // Base: dp[0] = 0
    // Recurrence: dp[i] = min over all coins c where c<=i of (dp[i-c] + 1)
    const int INF = 1e9;
    vector<int> dp(amount + 1, INF);
    dp[0] = 0;

    for (int i = 1; i <= amount; i++) {
        for (int c : coins) {
            if (c <= i && dp[i - c] != INF)
                dp[i] = min(dp[i], dp[i - c] + 1);
        }
    }

    if (dp[amount] == INF) cout << -1 << "\n";
    else cout << dp[amount] << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, W;
    cin >> n >> W;
    vector<int> wt(n), val(n);
    for (int i = 0; i < n; i++) cin >> wt[i] >> val[i];

    // SPACE-OPTIMIZED: 1D dp array, iterate weight BACKWARDS
    // dp[w] = max value with capacity w
    vector<int> dp(W + 1, 0);

    for (int i = 0; i < n; i++) {
        // Iterate backwards to prevent using item i more than once
        for (int w = W; w >= wt[i]; w--) {
            dp[w] = max(dp[w], dp[w - wt[i]] + val[i]);
        }
    }

    cout << dp[W] << "\n";
    return 0;
}

