// Given an array of n integers (possibly negative),
// find the maximum sum of any contiguous non-empty subarray.
// Input: n, then n integers
// Example: n=8, a={-2,1,-3,4,-1,2,1,-5,4} => output: 6  (subarray {4,-1,2,1})
// Example: n=3, a={-1,-2,-3} => output: -1
// Constraints: 1<=n<=1e5, -1e9<=a[i]<=1e9

sections.solution:
#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; cin >> n;
    vector<long long> a(n);
    for (auto& x : a) cin >> x;

    long long cur = a[0], best = a[0];
    for (int i = 1; i < n; i++) {
        cur = max(a[i], cur + a[i]);  // extend or restart
        best = max(best, cur);
    }
    cout << best << "\n";
    return 0;
}

