// Given an n×m grid where each cell has a non-negative cost,
// find the minimum cost path from (0,0) to (n-1,m-1).
// You can only move right or down.
// Input: n m, then n rows of m integers each.
// Example: n=3 m=3
// Grid: 1 3 1
//       1 5 1
//       4 2 1
// Output: 7  (path: 1->3->1->1->1 = 7)
// Constraints: 1<=n,m<=1000, 0<=cost<=100

sections.solution:
#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n, m; cin >> n >> m;
    vector<vector<int>> g(n, vector<int>(m));
    for (auto& row : g) for (auto& x : row) cin >> x;

    vector<vector<long long>> dp(n, vector<long long>(m, 1e18));
    dp[0][0] = g[0][0];

    for (int j = 1; j < m; j++) dp[0][j] = dp[0][j-1] + g[0][j];
    for (int i = 1; i < n; i++) dp[i][0] = dp[i-1][0] + g[i][0];

    for (int i = 1; i < n; i++)
        for (int j = 1; j < m; j++)
            dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + g[i][j];

    cout << dp[n-1][m-1] << "\n";
    return 0;
}
